+import { beforeEach, describe, expect, it, vi } from "vitest";
+import { maybeRunDoctorStartupChannelMaintenance } from "./doctor-startup-channel-maintenance.js";
+
+const runChannelPluginStartupMaintenance = vi.hoisted(() => vi.fn());
